# DRRA Shannon Entropy Sensor
# Returns files written in the last 60 seconds with entropy > 0.85

function Get-FileEntropy {
    param([string]$FilePath)
    try {
        $bytes = [System.IO.File]::ReadAllBytes($FilePath)
        if ($bytes.Length -lt 256) { return 0.0 }
        $freqs = @{}
        foreach ($b in $bytes) { $freqs[$b] = $freqs[$b] + 1 }
        $entropy = 0.0
        foreach ($count in $freqs.Values) {
            $p = $count / $bytes.Length
            if ($p -gt 0) { $entropy -= $p * [Math]::Log($p, 2) }
        }
        return [Math]::Round($entropy / 8, 4)
    } catch { return -1 }
}

$threshold = 0.85
$lookback  = (Get-Date).AddSeconds(-60)
$watched   = @('C:\Users', 'C:\ProgramData', 'D:\')

$results = @()
foreach ($root in $watched) {
    if (-not (Test-Path $root)) { continue }
    $files = Get-ChildItem -Path $root -Recurse -File -ErrorAction SilentlyContinue |
             Where-Object { $_.LastWriteTime -gt $lookback -and $_.Length -gt 1024 }
    foreach ($file in $files) {
        $e = Get-FileEntropy -FilePath $file.FullName
        if ($e -gt $threshold) {
            $results += "$($file.FullName)|$e|$($file.LastWriteTime)"
        }
    }
}

if ($results.Count -eq 0) { 'No high-entropy writes detected' } else { $results -join "`n" }

$extensions = @('.locked','.enc','.encrypted','.crypto','.crypt','.ryk','.RYK','.conti','.hive','.lockbit','.blackcat','.royal','.ALPHV')
$roots = @('C:\Users', 'D:\')
$count = 0
$found = @()

foreach ($root in $roots) {
    if (-not (Test-Path $root)) { continue }
    foreach ($ext in $extensions) {
        $files = Get-ChildItem -Path $root -Recurse -Filter "*$ext" -ErrorAction SilentlyContinue
        $count += $files.Count
        if ($files.Count -gt 0) { $found += "$ext`:$($files.Count)" }
    }
}

if ($count -eq 0) { '0' } else { "$count|$($found -join ',')|ALERT" }

$copies = Get-WmiObject -Class Win32_ShadowCopy -ErrorAction SilentlyContinue
$count = if ($copies) { @($copies).Count } else { 0 }
if ($count -eq 0) { "0|CRITICAL: No shadow copies - recovery blocked" } else { $count.ToString() }

$patterns = @('HOW_TO_DECRYPT*','DECRYPT_FILES*','README.TXT','RECOVERY_INSTRUCTIONS*','YOUR_FILES*','HOW_TO_RESTORE*','!!! IMPORTANT !!!')
$roots = @('C:\Users', 'C:\ProgramData', 'C:\')
$found = @()

foreach ($root in $roots) {
    foreach ($pattern in $patterns) {
        $files = Get-ChildItem -Path $root -Recurse -Filter $pattern -ErrorAction SilentlyContinue -Depth 5
        foreach ($f in $files) { $found += $f.FullName }
    }
}

if ($found.Count -eq 0) { 'No ransom notes found' } else { ($found | Select-Object -First 5) -join '|' }

$common_ports = @(80, 443, 53, 8080, 8443, 25, 587, 993, 995)
$suspicious = @()

$connections = Get-NetTCPConnection -State Established -ErrorAction SilentlyContinue |
    Where-Object { $_.RemoteAddress -notmatch '^(10\.|172\.(1[6-9]|2[0-9]|3[01])\.|192\.168\.|127\.|::1)' }

foreach ($conn in $connections) {
    if ($conn.RemotePort -notin $common_ports) {
        $proc = Get-Process -Id $conn.OwningProcess -ErrorAction SilentlyContinue
        $suspicious += "$($conn.RemoteAddress):$($conn.RemotePort)|$($proc.Name)|PID:$($conn.OwningProcess)"
    }
}

if ($suspicious.Count -eq 0) { 'No suspicious outbound connections' } else { $suspicious -join "`n" }

$services = @('VSS', 'wbengine', 'SDRSVC', 'swprv')
$results = @()

foreach ($svc in $services) {
    $s = Get-Service -Name $svc -ErrorAction SilentlyContinue
    if ($s) {
        $status = if ($s.Status -eq 'Running') { 'OK' } else { "ALERT:$($s.Status)" }
        $results += "$svc|$($s.Status)|$($s.StartType)|$status"
    } else {
        $results += "$svc|NOT_FOUND|N/A|WARNING"
    }
}
$results -join "`n"
